INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-c5fb3965-moex-00238', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '「我知道有一日我的花冠也將凋落，／而我並不感到心驚。／因為花朵的美麗只是樹身的一部，／生 命的成長，蓬勃與凋萎，／一如星月依循著自然的軌道前行，／遠勝過花朵的歡欣的——／是我能成 為更大的樹，／蔭庇更多的行人，／承載更多的歌聲，／冬日來到——／我便褪下了枝葉，／無聲地 安息／而我驕傲於／我是一棵獨立的樹——／不是藤蘿。」 下列選項，何者符合上述文句所欲表達之主旨？', '["人事無常，無須執著", "自主意識，不求依附", "真摯情感，難以改變", "滄海桑田，轉眼成空"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00239', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '承上題，為何花朵凋落，文中的「我」卻不覺心驚？', '["安時處順，和光同塵", "花開花落，自然遞嬗", "春華秋實，必有收穫", "繁華落盡，終將幻滅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00240', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '「從沒聽說誰家的蟑螂咬傷了嬰兒的事情。日常潛入鳥籠鴿舍，也只撿點掉下來的糧食，絕不傷害鳥 兒。故我稱之為□，誰曰不宜！」 依文意推敲，上文□中最適合填入的選項是：', '["仁", "義", "禮", "智"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00241', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '「六十五歲至一百歲都叫老，細分卻有霜紅之葉與枯木的差別；即使處於同一年齡層，一個充滿活力 視退休為第二個人生的開始，遂積極規劃、學習、籌備，展現出探險隊員一般的遠征樂趣，與一個自 覺日漸衰老、鑽入蝸牛老殼自怨自艾的人相比，其差異之大宛如星際。」這段話主要是要告訴我們：', '["我們要關心社會上有許多人過著自怨自艾的退休生活", "要有美好的退休生活，就要懂得欣賞霜紅之葉與枯木之美", "老人雖有年齡、體能狀態之分，但更關鍵的是自我的心態", "老人是社會的重要資產，人生經驗使他們有如探險隊員般的勇氣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00242', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '「當你讀一本歷史書，讀到書中的古人面臨重要的抉擇關頭時，請你這時立刻把書蓋上。好好想一想， 如果你身處對方的位置時，你會如何決定？做什麼樣的決定？把一切都想清楚後，再把書打開，看看 這個人物是怎麼做的，他最後做了什麼樣的決定？他的決定帶來的是成功或是失敗？原因何在？然後 比較自己與古人，在選擇和方法上有何異同之處？」 本文主要強調閱讀歷史的方法是：', '["歸納", "思辨", "冥想", "演繹"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00243', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '「他自承取筆名是為了不炫耀的緣故，他認為在那個年代，對於炫耀抱持著強烈敵意，一個擁有真實 能力的人，會有內在光芒吸引人去發現，絕對不能也不會敲鑼打鼓的在外炫耀。炫耀只會吸引一時， 膚淺的肯定，只會使人失去了繼續追求真實本事的毅力。躲在筆名後面，可以不用擔心是否浮誇地追 求不相稱的稱讚。他對女兒說：『或許你會慢慢理解，我當年躲在筆名後面躲避稱讚，那種幼稚卻真 誠的信念。』」 下列敘述，何者不符合文意？', '["有能力的人會有內在光芒吸引人去發現，不需炫耀", "膚淺的肯定，會使人失去繼續追求真實本事的毅力", "隱身筆名後面，躲避稱讚是一種幼稚不真誠的想法", "使用筆名，可以不用擔心是否浮誇地追求不相稱的稱讚"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00244', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '「旅行的荒謬和驚喜在我們必須千里跋涉以換取『在』的心境。必須到一個遙遠陌生的地方以實現生 命在現實中失落或從來欠缺的氣象：一種美，一種境界。」 下列選項，何者不能與此文中「在」的觀點相通？', '["在一個陌生的地方，走過陌生的街道，以平常沒有的雍容和悠閒，不急著到哪裡去", "我迷上了喜馬拉雅的國度，西藏、不丹、印度拉達克，站在陡峭銳利寸草不生的山稜上，八方空漠， 一切話語皆失去了意義。無聲的涅槃", "生活在他方，歇腳只不過是一時的權宜之計罷了，我們總是還來不及往土裡面扎根，就又要倉皇地 拎起行囊，在時間和空間的夾縫之中逃遁", "旅途中變化無窮的景致，未必能轉移你固執的視點而達至所謂的「目不暇給」。看東看西一陣後， 你總還是看回你自己、看回你心中一直還企盼的某一世界"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00245', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '「黑猩猩活在『當下、眼前』的世界裡，也因為這樣，非常善於記憶眼前瞬間出現的數字。他們絕不 會像人類一樣，考慮百年後的未來，或是緬懷百年前的歷史。所以人類會對未來懷抱希望——無論處 在多麼艱困的情況下，都能抱持勇氣。人，何以為人？那就是想像的力量。」下列選項，最接近本文 旨意的是：', '["人類擁有想像力，具備想像未來的力量，才能懷抱希望開創潛能", "黑猩猩的特質就是活在當下，不計較得失，也就沒有恐懼與失望", "黑猩猩因活在當下，所以沒有對未來的憂慮，值得我們人類效法", "人類因擁有想像力，無法像黑猩猩只活在當下，所以會悲傷焦慮"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00246', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '「因為噪音，讓我們拒絕聆聽。也因為拒絕聆聽，我們連擁有什麼，或是失去什麼都不知道。因為我 們不善於聆聽，也無法解讀聲音背後的訊息與力量。志銘在書上寫著：『聽聞鳥鳴聲背後所代表的意 義，毋寧更取決於當時的社會環境。』不懂得聆聽鳥語，是否也是我們這個世代的失落呢？如今，我 們應該努力去做的，是找回屬於這片土地的聲音。不論是自然天籟或是人文上的音景。這些資料，有 著文化創造與美學建構上的意義，更重要的是，留下這些歷史的跫音，讓我們不僅有了回味的空間， 也可以展現歲月演進的痕跡。」本文主旨是：', '["不論社會環境如何改變，大多數人對於欣賞聲景的態度都不會動搖", "不論是自然或人文的聲景，都具有值得去品味、感受的訊息與力量", "社會經濟環境的不同，必然影響人們養鳥的意願及欣賞鳥語的態度", "只要大家懂得聆聽土地的聲音，就能不斷創造出新的社會聲情文化"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00247', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '臺北市政府要求轄下各機關免用一次性餐具，發文時應採用的公文類別是：', '["呈", "函", "咨", "簽"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL)
